var BOT_ENABLED = true;
var BOT_SPEED   = 0;
var BOT_TIMER   = -1;


function botNw(g){var t=g.length,e=[],r=[],n=0;for(var a=0;a<t;a++){var o=g[a];(a%6===0||o!==n)&&(r.length>=3&&(r.unshift(n),e.push(r.slice())),r.length=0),o!==0&&(n=o,r.push(a));}r.length>=3&&(r.unshift(n),e.push(r.slice()));return e;}
function botAw(g){var t=g.length,e=[],r=[];for(var n=6;n>0;n--){var a=0,o=t-n;for(;o>=0;){var l=g[o];if(l===0)break;l!==a&&(r.length>=3&&(r.unshift(a),e.push(r.slice())),r.length=0),r.push(o),a=l,o-=6;}r.length>=3&&(r.unshift(a),e.push(r.slice())),r.length=0;}return e;}
function botOw(g){var t=g.length,e=[],r=[],n=0;for(;n<t;){var a=n,o=false,l=0;r.length=0;do{var s=a+6-1;o=a%6===0||s>=t;var u=g[a];u!==l&&(r.length>=3&&(r.unshift(l),e.push(r.slice())),r.length=0),l=u,l!==0&&r.push(a),a=s;}while(!o);r.length>=3&&(r.unshift(l),e.push(r.slice())),n<5?n++:n+=6;}return e;}
function botSw(g){var t=g.length,e=[],r=[],n=5;for(;n<=t-6;){var a=n,o=false,l=0;r.length=0;do{var s=a+6+1;o=a%6===5||s>=t;var u=g[a];u!==l&&(r.length>=3&&(r.unshift(l),e.push(r.slice())),r.length=0),l=u,l!==0&&r.push(a),a=s;}while(!o);r.length>=3&&(r.unshift(l),e.push(r.slice())),n<6&&n>0?n--:n+=6;}return e;}
function botMatches(g){return botNw(g).concat(botAw(g),botOw(g),botSw(g));}
function botClear(g,m){for(var i=0;i<m.length;i++)for(var j=1;j<m[i].length;j++)g[m[i][j]]=0;}
function botGravity(g){for(var n=g.length-1;n>=0;n--){if(g[n]!==0)continue;for(var o=n;o>=6;){o-=6;var l=g[o];if(l!==0){g[o]=0;g[n]=l;break;}}}}
function botCascade(g){var cleared=0,combo=0;for(var i=0;i<30;i++){var m=botMatches(g);if(m.length===0)break;for(var j=0;j<m.length;j++)cleared+=m[j].length-1;botClear(g,m);botGravity(g);combo++;}return{cleared:cleared,combo:combo};}


function botPlacementIdx(g, col) {
  var SIZE = g.length;       
  var COLS = 6;
  var bottom = SIZE - COLS;  
  var landIdx = -1;
  for (var r = 0; r < SIZE / COLS; r++) {
    var idx = bottom - r * COLS + col;  
    if (idx < 0) break;
    if (g[idx] === 0) { landIdx = idx; break; }  
  }

  if (landIdx < 0) return -1;            
  if (landIdx - 12 < 0) return -1;      
  if (g[landIdx - 6]  !== 0) return -1; 
  if (g[landIdx - 12] !== 0) return -1; 

  return landIdx;
}


function botHeights(g) {
  var h = new Array(6).fill(0);
  var bottom = g.length - 6;
  for (var col = 0; col < 6; col++) {
    for (var r = 0; r < 13; r++) {
      var idx = bottom - r * 6 + col;
      if (idx < 0 || g[idx] === 0) break;
      h[col]++;
    }
  }
  return h;
}


function botClusters(g) {
  var s = 0;
  for (var i = 0; i < g.length; i++) {
    var c = g[i]; if (c === 0) continue;
    if (i % 6 < 5 && g[i + 1] === c) s++;
    if (i + 6 < g.length && g[i + 6] === c) s++;
  }
  return s;
}


function botNeighborBonus(g, pidx, active) {
  var score = 0;
  var deltas = [-1, 1, -6, 6];
  for (var p = 0; p < 3; p++) {
    var pos = pidx - p * 6;
    var color = active[p];
    if (pos < 0 || pos >= g.length) continue;
    for (var d = 0; d < deltas.length; d++) {
      var np = pos + deltas[d];
      if (np < 0 || np >= g.length) continue;
      if (deltas[d] === 1  && pos % 6 === 5) continue;
      if (deltas[d] === -1 && pos % 6 === 0) continue;
      if (g[np] === color) score += 4;
    }
  }
  return score;
}


function botEval(baseGrid, seat, col, rot) {
  var active = N.getActive(seat, rot);
  var pidx = botPlacementIdx(baseGrid, col);
  if (pidx < 0) return -Infinity;

  var g = baseGrid.slice();
  var nb = botNeighborBonus(g, pidx, active);

  g[pidx]     = active[0];
  g[pidx - 6] = active[1];
  g[pidx - 12]= active[2];

  var res = botCascade(g);

  var heights = botHeights(g);
  var maxH    = Math.max.apply(null, heights);
  var avgH    = heights.reduce(function(a,b){return a+b},0) / 6;
  var variance= heights.reduce(function(a,h){return a+(h-avgH)*(h-avgH)},0) / 6;
  var clusters= botClusters(g);

  
  var danger = 0;
  for (var i = 0; i < 18; i++) if (g[i] !== 0) danger += 60;

  return (
    res.cleared * 20 +
    res.combo * res.combo * 30 +
    nb +
    clusters * 3 -
    variance * 5 -
    maxH * 3 -
    danger
  );
}


function botEvalLookahead(baseGrid, seat, col, rot) {
  var active = N.getActive(seat, rot);
  var pidx = botPlacementIdx(baseGrid, col);
  if (pidx < 0) return -Infinity;

  
  var g = baseGrid.slice();
  var nb = botNeighborBonus(g, pidx, active);
  g[pidx]     = active[0];
  g[pidx - 6] = active[1];
  g[pidx - 12]= active[2];
  var res = botCascade(g);

  var heights = botHeights(g);
  var maxH    = Math.max.apply(null, heights);
  var avgH    = heights.reduce(function(a,b){return a+b},0) / 6;
  var variance= heights.reduce(function(a,h){return a+(h-avgH)*(h-avgH)},0) / 6;
  var clusters= botClusters(g);
  var danger  = 0;
  for (var i = 0; i < 18; i++) if (g[i] !== 0) danger += 60;

  var immediate = (
    res.cleared * 20 + res.combo * res.combo * 30 +
    nb + clusters * 3 - variance * 5 - maxH * 3 - danger
  );

  
  var bestNext = -Infinity;
  for (var r2 = 0; r2 < 3; r2++) {
    for (var c2 = 0; c2 < 6; c2++) {
      var s2 = botEval(g, seat, c2, r2);
      if (s2 > bestNext) bestNext = s2;
    }
  }
  if (bestNext === -Infinity) bestNext = 0;

  return immediate + bestNext * 0.5;
}


function botPickBest() {
  var seat = N.local;
  if (seat < 0 || N.isSeatOut(seat) || N.phase !== 3 || N.gameOver) return null;

  var grid = N.grids[seat];
  var bestScore = -Infinity;
  var bestCol = 0, bestRot = 0;

  for (var rot = 0; rot < 3; rot++) {
    for (var col = 0; col < 6; col++) {
      var sc = botEvalLookahead(grid, seat, col, rot);
      if (sc > bestScore) { bestScore = sc; bestCol = col; bestRot = rot; }
    }
  }

  if (bestScore === -Infinity) return null;

  return { pidx: botPlacementIdx(grid, bestCol), rotation: bestRot };
}

function botStep() {
  if (!BOT_ENABLED) return;
  var seat = N.local;
  if (seat < 0 || N.isSeatOut(seat) || N.phase !== 3 || N.gameOver || !_i) return;

  var move = botPickBest();
  if (!move || move.pidx < 0) return;

  
  for (var r = 0; r < move.rotation; r++) { ++Yo; xt[seat].cycle(); }

  gT(move.pidx);
}

function botStart() {
  BOT_ENABLED = true;
  plato.log('[BOT] started speed=' + BOT_SPEED + 'ms');
  if (BOT_TIMER >= 0) plato.clearTimer(BOT_TIMER);
  BOT_TIMER = plato.setTimer(botStep, BOT_SPEED, true);
}

function botStop() {
  BOT_ENABLED = false;
  if (BOT_TIMER >= 0) { plato.clearTimer(BOT_TIMER); BOT_TIMER = -1; }
  plato.log('[BOT] stopped');
}

function botSetSpeed(ms) { BOT_SPEED = ms; if (BOT_ENABLED) { botStop(); botStart(); } }

plato.globals.bot = { start: botStart, stop: botStop, setSpeed: botSetSpeed };

N.onPhaseChange.receive(function(phase) {
  if (phase === 3 && BOT_ENABLED) botStart();
});

